from collections import deque

def topological_sort(graph):
    """
    Returns a list of nodes in valid topological order given:
        graph = {node: [nodes that node must come before]}

    This is equivalent to "edges going backwards" from the dependency structure.
    If 'a' depends on ['b', 'c'], then b and c are prerequisites, so we visit b/c first.
    """
    # Build reverse map: who depends on whom (prerequisite -> dependents)
    prereq_to_dependents = {node: [] for node in graph}
    for node, dependents in graph.items():
        for dep in dependents:
            prereq_to_dependents[dep].append(node)

    # Use Kahn's algorithm with a queue of all nodes that have no prerequisites
    q = deque()
    for node in graph:
        if not prereq_to_dependents[node]:
            q.append(node)

    result = []
    while q:
        u = q.popleft()
        result.append(u)
        # Add dependents of u to queue (they are ready now that u is processed)
        for v in prereq_to_dependents[u]:
            if v not in result:  # avoid duplicates during processing
                q.append(v)

    return result
```

