def rotate_matrix_clockwise(M):
    if not M or len(M) == 0:
        return []

    n = len(M)
    new_M = [[None] * n for _ in range(n)]

    # Rotate 90 degrees clockwise: new[i][j] = old[n-1-j][i]
    for i in range(n):
        for j in range(n):
            new_M[j][n - 1 - i] = M[i][j]

    return new_M
```

